import { cx } from '@emotion/css'
import type { IColor } from '@kyokuya/core-util'
import { mergeStyleSets } from '@kyokuya/core-util'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import type { ColorResult } from 'react-color'
import { SketchPicker } from 'react-color'

export interface IColorPickerProps {
  visible: boolean
  color: IColor
  className?: string
  onVisibleChange(visible: boolean): void
  onColorChange(color: IColor): void
}

export const ColorPicker: React.FC<IColorPickerProps> = props => {
  const { color, onColorChange, onVisibleChange } = props

  const events = {
    onClosePicker: useEvent(() => onVisibleChange(false)),
    onColorChange: useEvent((color: ColorResult): void => {
      onColorChange(color.rgb)
    }),
  }

  const classes = useStyles(props.visible)

  return (
    <div className={cx(classes.popover, props.className)}>
      <div className={classes.cover} onClick={events.onClosePicker} />
      <div className={classes.picker} onDoubleClick={events.onClosePicker}>
        <SketchPicker
          className={classes.colorPicker}
          color={color}
          onChange={events.onColorChange}
        />
      </div>
    </div>
  )
}

const useStyles = (visible: boolean) => {
  return React.useMemo(
    () =>
      mergeStyleSets({
        popover: {
          position: 'absolute',
          zIndex: 20,
          top: 20,
          display: visible ? 'block' : 'none',
          visibility: visible ? 'visible' : 'hidden',
        },
        cover: {
          position: 'fixed',
          top: '0px',
          right: '0px',
          bottom: '0px',
          left: '0px',
        },
        picker: {
          display: 'flex',
          flexDirection: 'column',
          minWidth: 220,
          border: '1px solid #e6e6e6',
          borderRadius: 4,
          boxShadow: 'rgba(0, 0, 0, 0.15) 0px 0px 0px 1px, rgba(0, 0, 0, 0.15) 0px 8px 16px',
          background: '#fff',
        },
        colorPicker: {
          '&&': {
            border: 'none !important',
            borderRadius: '0px !important',
            boxShadow: 'none !important',
          },
        },
      }),
    [visible],
  )
}
