import debounce from '@kyokuya/_shared/util/debounce'
import { useEffect, useState } from 'react'

/**
 * 滚动进度
 * @param eleRef
 * @param delay
 * @returns
 */
export function useScrollProgress(eleRef: React.RefObject<HTMLElement> | null, delay = 0): number {
  const [progress, setProgress] = useState<number>(0)

  useEffect(() => {
    const element = eleRef === null ? document.documentElement : eleRef.current
    if (element == null) return

    const handleScroll: () => void = debounce((): void => {
      const scrolledHeight: number = element.scrollTop
      const totalScrollableHeight: number = element.scrollHeight - element.clientHeight
      setProgress(scrolledHeight / totalScrollableHeight)
    }, delay)

    handleScroll()
    const eventHostElement = element === document.documentElement ? window : element

    eventHostElement.addEventListener('scroll', handleScroll)

    return () => eventHostElement.removeEventListener('scroll', handleScroll)
  }, [eleRef, delay])
  return progress
}

export default useScrollProgress
