import { ColorPicker } from '@kyokuya/core-component'
import type { IColor } from '@kyokuya/core-util'
import { calcCssColor, mergeStyleSets } from '@kyokuya/core-util'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import type { IFormItemRendererProps } from './types'

export type IFormItemColorProps = IFormItemRendererProps<IColor>

interface IParams {
  componentName?: string
}

export const createFormItemColor = ({ componentName }: IParams): React.FC<IFormItemColorProps> => {
  const FormItemColor: React.FC<IFormItemColorProps> = props => {
    const { value: color, disabled } = props
    const [pickerVisible, setPickerVisible] = React.useState<boolean>(false)

    const events = {
      onTogglePickerVisible: useEvent(() => {
        if (disabled) return
        setPickerVisible(v => !v)
      }),
      onColorChange: useEvent((color: IColor): void => {
        if (disabled) return
        props.onChange(color)
      }),
    }

    const classes = useStyles(color, disabled)
    return (
      <div className={classes.container}>
        <div className={classes.swatch} onClick={events.onTogglePickerVisible}>
          <div className={classes.colorSquare} />
        </div>
        <ColorPicker
          className={classes.picker}
          visible={pickerVisible}
          color={color}
          onVisibleChange={setPickerVisible}
          onColorChange={events.onColorChange}
        />
      </div>
    )
  }
  FormItemColor.displayName = componentName ?? 'FormItemColor'
  return FormItemColor
}

const useStyles = (color: IColor, disabled: boolean | undefined) => {
  return mergeStyleSets({
    container: {
      display: 'flex',
      alignItems: 'center',
    },
    swatch: {
      display: 'inline-block',
      padding: 3,
      border: '1px solid rgba(0,0,0,.2)',
      borderRadius: '1px',
      background: '#fff',
      cursor: disabled ? 'default' : 'pointer',
    },
    colorSquare: {
      width: 32,
      height: 12,
      borderRadius: 2,
      backgroundColor: calcCssColor(color),
    },
    picker: {
      '&&': {
        left: 30,
      },
    },
  })
}
