import type { IHostStore, ISerializer, IStorage } from './types'

/**
 * Create a empty storage.
 * @returns
 */
export const createEmptyStorage = <T>(): IStorage<T> => ({
  load: () => Promise.resolve(null),
  save: () => Promise.resolve(),
})

/**
 * Create a storage.
 *
 * @param store
 * @param key
 * @param serializer
 * @returns
 */
export const createStorage = <T>(
  store: IHostStore,
  key: string,
  serializer: ISerializer<T>,
): IStorage<T> => ({
  load: async (): Promise<T | null> => {
    const content = await store.get(key)
    if (content == null) return null
    try {
      return serializer.parse(content)
    } catch (error) {
      console.error(`JSON.parse error: Bad storage ${key}`, error)
      return null
    }
  },
  save: async (data: T): Promise<void> => {
    const content: string = serializer.stringify(data)
    await store.set(key, content)
  },
})

export function createLocalStorage<T>(key: string, serializer: ISerializer<T> = JSON): IStorage<T> {
  if (typeof localStorage === 'undefined') {
    console.error('Cannot find `localStorage`.')
    return createEmptyStorage<T>()
  }

  const hostStore: IHostStore = {
    get: key => localStorage.getItem(key),
    set: (key, value) => localStorage.setItem(key, value),
  }
  return createStorage(hostStore, key, serializer)
}
