import { cx } from '@emotion/css'
import { mergeStyleSets } from '@kyokuya/core-util'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import type { IFormItemRendererProps, IFormItems } from './types'

export interface IFormClasses {
  formItem?: string
  label?: string
  content?: string
}

export interface IFormProps<D> {
  data: D
  items: IFormItems<D>
  itemsOrder: Array<keyof D>
  classes?: IFormClasses
  colon?: React.ReactNode
  onChange(data: Partial<D>): void
}

export function Form<D>(props: IFormProps<D>): React.ReactElement {
  const { data, items, itemsOrder, colon = ':', onChange } = props

  const classes = {
    formItem: cx(baseClasses.formItem, props.classes?.formItem),
    label: cx(baseClasses.label, props.classes?.label),
    content: cx(baseClasses.content, props.classes?.content),
  }
  const formItems = itemsOrder.map((key: keyof D, idx: number): React.ReactElement => {
    const item = items[key]
    return (
      <div key={idx} className={classes.formItem}>
        <div className={classes.label}>
          {item.label}
          {colon}
        </div>
        <div className={classes.content}>
          <FormItemContent
            name={key}
            value={data[key]}
            disabled={item.disabled}
            required={item.required}
            ContentRenderer={item.ContentRenderer}
            onChange={onChange}
          />
        </div>
      </div>
    )
  })
  return <React.Fragment>{formItems}</React.Fragment>
}

interface IFormItemContentProps<D, K extends keyof D> {
  name: K
  value: D[K]
  disabled?: boolean
  required?: boolean
  ContentRenderer: React.ComponentType<IFormItemRendererProps<D[K]>>
  onChange(data: Partial<D>): void
}

function FormItemContent<D, K extends keyof D>(
  props: IFormItemContentProps<D, K>,
): React.ReactElement {
  const { ContentRenderer } = props
  const onChange = useEvent((value: D[K]): void => {
    props.onChange({ [props.name]: value } as unknown as Partial<D>)
  })
  return (
    <ContentRenderer
      value={props.value}
      disabled={props.disabled}
      required={props.required}
      onChange={onChange}
    />
  )
}

const baseClasses = mergeStyleSets({
  formItem: {
    display: 'flex',
    alignItems: 'flex-start',
  },
  label: {
    flex: '0 1 auto',
    display: 'inline-flex',
    justifyContent: 'flex-end',
    alignItems: 'flex-start',
    marginRight: 8,
    userSelect: 'none',
    height: '100%',
  },
  content: {
    flex: '1 1 auto',
    display: 'inline-flex',
    justifyContent: 'flex-start',
    alignItems: 'flex-start',
    height: '100%',
  },
})
