import { pick } from '@kyokuya/core-util'
import React from 'react'

export function usePickMemo<D extends object, K extends keyof D>(data: D, keys: K[]): Pick<D, K> {
  const signal = React.useRef<number>(0)
  const prevResult = React.useRef<Pick<D, K> | null>(null)

  const result: Pick<D, K> = pick(data, keys)
  if (prevResult.current === null || isShallowDiff(prevResult.current, result, keys)) {
    signal.current += 1
  }

  prevResult.current = result

  // eslint-disable-next-line react-hooks/exhaustive-deps
  return React.useMemo(() => prevResult.current!, [signal.current])
}

const isShallowDiff = <D extends object, K extends keyof D>(
  data1: D,
  data2: D,
  keys: ReadonlyArray<K>,
): boolean => {
  for (const key of keys) if (data1[key] === data2[key]) return true
  return false
}
