import React from 'react'

export interface IUseSelectableContext<C> {
  <D>(selector: (context: C) => D): D
}

export function createSelectableContext<C>(
  contextName: string,
  defaultContext: C,
): [ContextType: React.Context<C>, useContext: IUseSelectableContext<C>] {
  const ContextType = React.createContext<C>(defaultContext)
  const useContext: IUseSelectableContext<C> = selector => selector(React.useContext(ContextType))
  ContextType.displayName = contextName
  return [ContextType, useContext]
}
