import { Loading as DefaultLoading } from '@kyokuya/core-component'
import { enhanceReducerWithMultipleActions } from '@kyokuya/core-util'
import type { IUseSelectableContext } from '@kyokuya/react-hooks'
import { useHeaveState } from '@kyokuya/react-hooks'
import React from 'react'
import type { IStorage } from '../types'
import { createLocalStorage } from '../util'

export interface ILayoutComponentProps {
  children: React.ReactNode
}

export interface IProviderProps<D> {
  storageKey?: string
  initialData?: Partial<D> | Promise<Partial<D>>
  children?: React.ReactNode
  LayoutComponent?: React.ComponentType<ILayoutComponentProps>
}

interface IProviderInner1Props<S, D> {
  initialState: S
  storage: IStorage<Partial<D>> | null
  children: React.ReactNode
  LayoutComponent: React.ComponentType<ILayoutComponentProps>
}

interface IPersistentProps<D> {
  storage: IStorage<Partial<D>> | null
}

interface IParams<S, A, D> {
  ContextName: string
  ContextType: React.Context<{ state: S; dispatch: React.Dispatch<A | A[]> }>
  useContext: IUseSelectableContext<{ state: S; dispatch: React.Dispatch<A | A[]> }>
  initState(customizedData: Partial<D> | null, baseState?: Readonly<S>): S
  reducer: React.Reducer<S, A>
  serialize(state: S): Partial<D>
  LoadingComponent?: React.ComponentType
  LayoutComponent?: React.ComponentType<ILayoutComponentProps>
}

interface IState<D> {
  customizedData: Partial<D> | null | undefined
  remoteData: Partial<D> | null | undefined
  loadingCustomizedData: boolean
  loadingRemoteData: boolean
}

export function createPersistProvider<S, A, D>(
  params: IParams<S, A, D>,
): React.FC<IProviderProps<D>> {
  const {
    ContextName,
    ContextType,
    useContext,
    serialize,
    initState,
    LoadingComponent = DefaultLoading,
    LayoutComponent = React.Fragment,
  } = params
  const enhancedReducer = enhanceReducerWithMultipleActions(params.reducer)

  const ProviderWrapper: React.FC<IProviderProps<D>> = props => {
    const initialDataRef = React.useRef(props.initialData)
    const [storage] = React.useState<IStorage<Partial<D>> | null>(() =>
      props.storageKey ? createLocalStorage<Partial<D>>(props.storageKey) : null,
    )

    const [state, patchState] = useHeaveState<IState<D>>({
      customizedData: undefined,
      remoteData: undefined,
      loadingCustomizedData: true,
      loadingRemoteData: true,
    })

    // Loading customized data.
    React.useEffect(() => {
      let cancelled = false
      void Promise.resolve(initialDataRef.current)
        .then(data => {
          if (!cancelled) {
            patchState({
              customizedData: data,
              loadingCustomizedData: false,
            })
          }
        })
        .catch(error => {
          console.error(error)
          if (!cancelled) {
            patchState({
              customizedData: undefined,
              loadingCustomizedData: false,
            })
          }
        })
      return (): void => {
        cancelled = true
      }
    }, [patchState])

    // Loading remote data.
    React.useEffect(() => {
      let cancelled = false
      async function loadData(): Promise<void> {
        if (storage === null) {
          patchState({
            remoteData: undefined,
            loadingRemoteData: false,
          })
        } else {
          try {
            const remoteData = await storage.load()
            if (!cancelled) {
              patchState({
                remoteData,
                loadingRemoteData: false,
              })
            }
          } catch (error) {
            console.error(error)
            if (!cancelled) {
              patchState({
                remoteData: undefined,
                loadingCustomizedData: false,
              })
            }
          }
        }
      }
      void loadData()

      return (): void => {
        cancelled = true
      }
    }, [storage, patchState])

    const loading: boolean = (state.loadingRemoteData as boolean) || state.loadingCustomizedData
    if (loading) {
      return <LoadingComponent />
    }

    const baseState: S = initState(state.remoteData ?? null)
    const initialState: S = initState(state.customizedData ?? null, baseState)
    return (
      <Provider
        initialState={initialState}
        storage={storage}
        LayoutComponent={props.LayoutComponent ?? LayoutComponent}
      >
        {props.children}
      </Provider>
    )
  }

  const Provider: React.FC<IProviderInner1Props<S, D>> = props => {
    const { LayoutComponent } = props
    const [state, dispatch] = React.useReducer(enhancedReducer, props.initialState)
    const context = React.useMemo(() => ({ state, dispatch }), [state, dispatch])
    return (
      <ContextType.Provider value={context}>
        <Persistent storage={props.storage} />
        <LayoutComponent>{props.children}</LayoutComponent>
      </ContextType.Provider>
    )
  }

  const Persistent: React.FC<IPersistentProps<D>> = ({ storage }) => {
    const firstRef = React.useRef<boolean>(true)
    const saveLockRef = React.useRef<boolean>(false)
    const state = useContext(store => store.state)
    React.useEffect(() => {
      if (firstRef.current) firstRef.current = false
      else {
        if (storage != null && !saveLockRef.current) {
          saveLockRef.current = true
          const resolveData: Partial<D> = serialize(state)
          storage.save(resolveData).finally(() => {
            saveLockRef.current = false
          })
        }
      }
    }, [state, storage])
    return <React.Fragment />
  }

  ProviderWrapper.displayName = ContextName + 'ProviderWrapper'
  Provider.displayName = ContextName + 'Provider'
  Persistent.displayName = ContextName + 'ProviderPersistent'
  return ProviderWrapper
}
